using Contoso.Orders;

namespace Contoso.Orders.Tests;

[TestClass]
public sealed class OrderServiceTests
{
    private readonly OrderService _service;

    public OrderServiceTests()
    {
        _service = new OrderService();
    }

    private static List<OrderItem> CreateItems(params (string name, decimal price, int qty)[] items) =>
        items.Select(i => new OrderItem { ProductName = i.name, Price = i.price, Quantity = i.qty }).ToList();

    #region CreateOrder – validation

    [TestMethod]
    public void CreateOrder_NullCustomerId_ThrowsArgumentNullException()
    {
        var items = CreateItems(("Widget", 10m, 1));

        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder(null!, items));
        Assert.AreEqual("customerId", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_NullItems_ThrowsArgumentNullException()
    {
        var ex = Assert.ThrowsExactly<ArgumentNullException>(() => _service.CreateOrder("cust-1", null!));
        Assert.AreEqual("items", ex.ParamName);
    }

    [TestMethod]
    public void CreateOrder_EmptyItems_ThrowsInvalidOperationException()
    {
        var ex = Assert.ThrowsExactly<InvalidOperationException>(
            () => _service.CreateOrder("cust-1", []));
        Assert.Contains("no items", ex.Message, StringComparison.OrdinalIgnoreCase);
    }

    #endregion

    #region CreateOrder – happy path

    [TestMethod]
    public void CreateOrder_ValidInputs_ReturnsOrderWithCorrectCustomerId()
    {
        var items = CreateItems(("Widget", 25m, 2));

        var order = _service.CreateOrder("cust-1", items);

        Assert.AreEqual("cust-1", order.CustomerId);
    }

    [TestMethod]
    public void CreateOrder_ValidInputs_AssignsNonEmptyId()
    {
        var items = CreateItems(("Widget", 25m, 2));

        var order = _service.CreateOrder("cust-1", items);

        Assert.IsNotNull(order.Id);
        Assert.AreNotEqual(string.Empty, order.Id);
    }

    [TestMethod]
    public void CreateOrder_ValidInputs_SetsCreatedAtToUtcNow()
    {
        var before = DateTime.UtcNow;
        var items = CreateItems(("Widget", 10m, 1));

        var order = _service.CreateOrder("cust-1", items);

        var after = DateTime.UtcNow;
        Assert.IsTrue(order.CreatedAt >= before && order.CreatedAt <= after,
            $"CreatedAt {order.CreatedAt} should be between {before} and {after}.");
    }

    [TestMethod]
    public void CreateOrder_ValidInputs_StoresItemsOnOrder()
    {
        var items = CreateItems(("Widget", 10m, 1), ("Gadget", 20m, 3));

        var order = _service.CreateOrder("cust-1", items);

        Assert.HasCount(2, order.Items);
    }

    #endregion

    #region CreateOrder – total calculation

    [TestMethod]
    [DynamicData(nameof(TotalCalculationData))]
    public void CreateOrder_WithItems_CalculatesCorrectTotal(
        (string name, decimal price, int qty)[] items, decimal expectedTotal)
    {
        var orderItems = CreateItems(items);

        var order = _service.CreateOrder("cust-1", orderItems);

        Assert.AreEqual(expectedTotal, order.Total);
    }

    public static IEnumerable<((string name, decimal price, int qty)[] items, decimal expectedTotal)> TotalCalculationData =>
    [
        (new[] { ("Widget", 10m, 1) }, 10m),
        (new[] { ("Widget", 10m, 3) }, 30m),
        (new[] { ("Widget", 10m, 2), ("Gadget", 5m, 4) }, 40m),
        (new[] { ("Free", 0m, 5) }, 0m),
    ];

    #endregion

    #region GetOrder

    [TestMethod]
    public void GetOrder_ExistingId_ReturnsMatchingOrder()
    {
        var items = CreateItems(("Widget", 10m, 1));
        var created = _service.CreateOrder("cust-1", items);

        var retrieved = _service.GetOrder(created.Id);

        Assert.IsNotNull(retrieved);
        Assert.AreEqual(created.Id, retrieved.Id);
    }

    [TestMethod]
    public void GetOrder_NonExistingId_ReturnsNull()
    {
        var result = _service.GetOrder("does-not-exist");

        Assert.IsNull(result);
    }

    #endregion

    #region GetOrdersByCustomer

    [TestMethod]
    public void GetOrdersByCustomer_NoOrders_ReturnsEmptyList()
    {
        var result = _service.GetOrdersByCustomer("cust-999");

        Assert.IsEmpty(result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_SingleOrder_ReturnsSingleMatch()
    {
        var items = CreateItems(("Widget", 10m, 1));
        _service.CreateOrder("cust-1", items);

        var result = _service.GetOrdersByCustomer("cust-1");

        var order = Assert.ContainsSingle(result);
        Assert.AreEqual("cust-1", order.CustomerId);
    }

    [TestMethod]
    public void GetOrdersByCustomer_MultipleOrders_ReturnsAllMatches()
    {
        _service.CreateOrder("cust-1", CreateItems(("A", 10m, 1)));
        _service.CreateOrder("cust-1", CreateItems(("B", 20m, 1)));
        _service.CreateOrder("cust-2", CreateItems(("C", 30m, 1)));

        var result = _service.GetOrdersByCustomer("cust-1");

        Assert.HasCount(2, result);
    }

    [TestMethod]
    public void GetOrdersByCustomer_OtherCustomerOrders_AreExcluded()
    {
        _service.CreateOrder("cust-1", CreateItems(("A", 10m, 1)));
        _service.CreateOrder("cust-2", CreateItems(("B", 20m, 1)));

        var result = _service.GetOrdersByCustomer("cust-1");

        var order = Assert.ContainsSingle(result);
        Assert.AreEqual("cust-1", order.CustomerId);
    }

    #endregion
}

